	.TITLE	F16	.PROC	M680002		; mnmonics CALM 2	.RADIX	10.		; base 10 par dfaut	.HEX			; listing en hexadcima	.REF	SM100HARD	; df hard Smaky 100	.REF	SM8		; df diverses	.REF	NTREL		; df noyau temps rel	.REF	GESMEM		; df gestionnaire de mmoire	.REF	BIOS	.REF	FOS		; df file operating system	.REF	LIB		; df librairie	.REF	DRIVERS		; df drivers	.REV	1,0	.CODE	250,14,B'010,20,2000,20,2000,2,'*,0,0; Constantes; ----------F16	=	H'E0		; code de la touche (F16)SCRNZONE=	H'093A		; donne l'adresse de l'cranSCVDC	=	H'094A		; ^table VDC standardNBTYPE	=	4		; 4 types d'cran; Variables; ---------	.LOC	0OFLAGS:	.BLKB	1		; flags divers	.EVENONOTYPE:.BLKB	2		; type de l'cran utilisOBUCOM:	.BLKB	10LGVAR:; Programme; ---------	.LOC	0START:	.W	LIB,?OPELIB	; ouvre la librairie	LOAD.L	D4,#LGVAR	.W	GESMEM,?GETMEM	; demande mmoire pour var.	JUMP,NE	ER	LOAD.L	A6,A4		; A6 <-- ^variables	CLR.B	(A6)+OFLAGS	; clear tous les flags	CLR.W	(A6)+ONOTYPE	LOAD.L	A4,#(A6)+OBUCOM	; A4 <-- ^buffer pour commande	LOAD.B	(A4)+0,#KEYSIP	; rserve inter-programmes	LOAD.B	(A4)+1,#F16&H'7F; touche (F16) selon pseudo-code	CLR.B	(A4)+2		; termine les commandes	.W	LIB,?GCHKEY	; D6 <-- canal clavier	LOAD.W	D3,#TYPKEY	; D3 <-- type driver clavier	.W	FOS,?COMMAND	; donne commande d'assignation	JUMP,NE	ER	LOAD.W	D3,#1	.W	LIB,?ASSKEY	; redonne clavier au CLE !10$:	.W	LIB,?GCHKEY	; D6 <-- canal du clavier	.W	FOS,?GETTYPE	; D2 <-- no driver  D3 <-- type	.W	BIOS,?WFSKEY	; wait for special key ...	COMP.W	D3,#F16	JUMP,NE	10$	LOAD.W	D3,(A6)+ONOTYPE	INC.W	D3	COMP.W	D3,#NBTYPE	JUMP',LO 25$	CLR.W	D325$:	LOAD.W	(A6)+ONOTYPE,D3	LOAD.L	A3,SCVDC		; A3 <-- ^table VDC standard	TEST.W	D3	JUMP',EQ 30$	LOAD.L	A3,#R16"TA16KHZH	DEC.W	D3	JUMP',EQ 30$	LOAD.L	A3,#R16"TA16KHZB	DEC.W	D3	JUMP',EQ 30$	LOAD.L	A3,#R16"TA16KHZE30$:	CALL	INIVDC	JUMP	10$ER:	.W	LIB,?CLOLIB	.W	FOS,?STOP;--------\\; INIVDC  >;========/; Initialise le circuit VDC-6845e contrleur d'cran.; in	A3.L	^table; out	-; mod	-INIVDC:	PUSHM.L	D3,A3	CLR.B	D310$:	LOAD.B	VDC,D3	LOAD.B	VDCR,(A3+)	INC.B	D3	COMP.B	D3,#4+4+2	JUMP,LO	10$	CLR.L	D3	LOAD.W	D3,(A3)		; D3 <-- offset dbut cran	ADD.L	D3,SCRNZONE	; D3 <-- adresse dbut cran	SR.L	D3,#8	SR.L	D3,#3		; D3 <-- adresse / 2Kbytes	LOAD.B	VDC,#12	LOAD.B	VDCR,D3		; dbut cran (high)	POPM.L	D3,A3	RET; Tables; ------TA16KHZH:	.B	128/4-1	.B	96/4	.B	96/4+1	.B	5*H'10+5	.B	312/16-1	.B	312-(312/16)*16	.B	256/16	.B	(280)/16	.B	B'00000100	.B	16-1	.W	128*20TA16KHZB:	.B	128/4-1	.B	96/4	.B	96/4+1	.B	5*H'10+5	.B	312/16-1	.B	312-(312/16)*16	.B	256/16	.B	(280)/16	.B	B'00000100	.B	16-1	.W	128*112TA16KHZE:	.B	128/4-1	.B	96/4	.B	96/4+1	.B	5*H'10+5	.B	625/16-1	.B	625-(625/16)*16	.B	400/16	.B	(560)/16	.B	B'00000111	.B	16-1	.W	0	.END	START